#!/usr/bin/env node
/**
 * scripts/build-personal-growth-templates.mjs
 *
 * Regenerate the two public template files from
 * `scripts/personal-growth-prompts.mjs` (single source of truth):
 *
 *   templates/teams/personal-growth-team.yaml      (gotong.team/v1)
 *   templates/bundles/personal-growth.yaml         (gotong.bundle/v1)
 *
 * Run after editing prompts or agent shape:
 *   node scripts/build-personal-growth-templates.mjs
 *
 * The generated files include a "do-not-edit-by-hand" banner so future
 * me / contributors know to update prompts.mjs and re-run instead.
 */

import { writeFileSync, readFileSync, mkdirSync } from 'node:fs'
import { resolve, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'
// `yaml` is a dep of @gotong/web in the workspace; scripts/ has no
// package.json so resolve via the web package's node_modules.
import { stringify as stringifyYaml } from '../packages/web/node_modules/yaml/dist/index.js'

import {
  TEAM_AGENTS,
  TEAM_NAME,
  TEAM_DESCRIPTION,
  DEFAULT_PROVIDER,
} from './personal-growth-prompts.mjs'

const ROOT = resolve(fileURLToPath(import.meta.url), '..', '..')
const TEAM_OUT = resolve(ROOT, 'templates/teams/personal-growth-team.yaml')
const BUNDLE_OUT = resolve(ROOT, 'templates/bundles/personal-growth.yaml')
// Also embed the bundle into packages/web/static so the admin UI's
// "use built-in template" button can fetch it without touching disk
// at runtime. The web build script base64-embeds everything under
// static/, so this lands in the binary distribution too.
const BUNDLE_STATIC = resolve(ROOT, 'packages/web/static/builtin-bundles/personal-growth.yaml')
const WORKFLOW_SRC = resolve(ROOT, 'templates/workflows/personal-growth-flow.yaml')

const BANNER = `# ─────────────────────────────────────────────────────────────────────────────
# AUTO-GENERATED by scripts/build-personal-growth-templates.mjs
# Single source of truth: scripts/personal-growth-prompts.mjs
#
# DO NOT EDIT BY HAND. Edit the prompts/config in personal-growth-prompts.mjs
# and rerun:  node scripts/build-personal-growth-templates.mjs
#
# Last regenerated: ${new Date().toISOString()}
# ─────────────────────────────────────────────────────────────────────────────
`

const HEAD_COMMENT = `# 个人成长团队（7 位教练）
# Schema: gotong.team/v1
# Companion workflow: templates/workflows/personal-growth-flow.yaml
# Or use the bundle (team + workflow + UI hints in one file):
#   templates/bundles/personal-growth.yaml
#
# 谁用这套：任何一个想认真想想"我接下来 3-12 个月该往哪走"的人。
# 不是商业咨询、不是 AI 助手"帮我做决策" —— 它做的事很有限：
#   · 把你提供的 4 段自述读一遍，用一段画像告诉你"我听懂你了"
#   · 5 位维度教练（身体 / 心理 / 目标 / 资源 / 关系）各自看你一眼
#   · 综合规划师把 5 个视角织成一条 12 周墙上计划 + 5 个权衡判断 +
#     "v2 跑这条工作流时建议你回答的 5 个种子问题"
#
# 每位教练都被设计成「有边界的陪伴者」：
#   - 身体教练不诊断疾病，触及红旗（持续胸痛、不明出血等）会请你找医生
#   - 心理教练不诊断心理疾病，触及风险信号会请你找咨询师（含 24h 危机热线）
#   - 目标 / 资源 / 关系教练同样：不灌鸡汤、不冒充专家、不超出能力范围
#
# 默认 provider: DeepSeek (openai-compatible)
#   - 国内 API（不需要 VPN）
#   - deepseek-v4-flash 价格 ~ Claude Opus 的 1/10
#   - 申请 key：https://platform.deepseek.com
#
# 想换 Anthropic / OpenAI？把每个 agent 的 provider / baseURL / model 改掉
# 即可，system 提示词是 vendor-neutral 的，所有模型都能读懂。
#
# 派发方式：
#   capability=plan-personal-growth   触发完整 7 步流水线（推荐）
#   capability=user-portrait          单独要一份画像
#   capability=analyze-body           单独跑身体维度
#   ...其他 capability 见各 agent 的 capabilities 字段
`

/** Build one agent yaml dict from a TEAM_AGENTS entry. */
function agentDict(a) {
  const out = {
    id: a.id,
    displayName: a.displayName,
    capabilities: [...a.capabilities],
    kind: 'personal-growth',
    provider: DEFAULT_PROVIDER.provider,
    model: DEFAULT_PROVIDER.model,
    baseURL: DEFAULT_PROVIDER.baseURL,
    providerLabel: DEFAULT_PROVIDER.providerLabel,
    system: a.system,
  }
  if (a.uses && a.uses.length > 0) out.uses = a.uses
  if (a.mcpServers && a.mcpServers.length > 0) out.mcpServers = a.mcpServers
  return out
}

const teamDoc = {
  schema: 'gotong.team/v1',
  team: {
    name: TEAM_NAME,
    description: TEAM_DESCRIPTION,
    agents: TEAM_AGENTS.map(agentDict),
  },
}

// yaml.stringify options: lineWidth: 0 keeps long Chinese prompt lines
// from wrapping mid-character; `blockQuote: 'literal'` makes multi-line
// strings render as `|`-style blocks (much more readable than `>`).
const yamlOpts = { lineWidth: 0, blockQuote: 'literal', defaultStringType: 'PLAIN', defaultKeyType: 'PLAIN' }

mkdirSync(dirname(TEAM_OUT), { recursive: true })
writeFileSync(TEAM_OUT, BANNER + HEAD_COMMENT + '\n' + stringifyYaml(teamDoc, yamlOpts))
console.log(`wrote ${TEAM_OUT}`)

// ─────────────────────────────────────────────────────────────────────
// Bundle: team + workflow + apiKeyPrompt hint, all in one file.
// The workflow yaml is read verbatim from templates/workflows/, so any
// edit there flows into the bundle on the next regen.
// ─────────────────────────────────────────────────────────────────────

const workflowText = readFileSync(WORKFLOW_SRC, 'utf8')
// Pluck the top-level `workflow:` map out of the workflow yaml. Parse,
// then drop the `schema:` field since the bundle wraps it.
const { parse: parseYaml } = await import('../packages/web/node_modules/yaml/dist/index.js')
const workflowDoc = parseYaml(workflowText)
if (!workflowDoc || !workflowDoc.workflow) {
  throw new Error(`expected workflow: top-level key in ${WORKFLOW_SRC}`)
}

const bundleDoc = {
  schema: 'gotong.bundle/v1',
  bundle: {
    name: '个人成长(7 教练 + 12 周墙上计划)',
    description: `把 templates/teams/personal-growth-team.yaml + templates/workflows/personal-growth-flow.yaml 合一次 import。
Admin UI 上"导入团队"后,会引导你填一个 DeepSeek API key,自动应用到 7 个 agent。
工作流会同时注册,直接在工作流面板点"开始"就能跑。`,
    team: teamDoc.team,
    workflow: workflowDoc.workflow,
    defaults: {
      apiKeyPrompt: {
        provider: 'openai-compatible',
        baseURL: DEFAULT_PROVIDER.baseURL,
        label: 'DeepSeek',
      },
    },
  },
}

const BUNDLE_BANNER = `# ─────────────────────────────────────────────────────────────────────────────
# AUTO-GENERATED by scripts/build-personal-growth-templates.mjs
# Single source of truth: scripts/personal-growth-prompts.mjs (team)
#                        templates/workflows/personal-growth-flow.yaml (workflow)
# DO NOT EDIT BY HAND. Re-run the generator instead.
# Last regenerated: ${new Date().toISOString()}
# ─────────────────────────────────────────────────────────────────────────────
`

const BUNDLE_DOC_COMMENT = `# 个人成长 bundle (1 团队 + 1 工作流 + UI 引导)
# Schema: gotong.bundle/v1
#
# 怎么用:
#   1. 在 admin UI 上点"导入团队"按钮(工作流 tab)
#   2. 上传或粘贴这个文件
#   3. 模态会问你"DeepSeek API key" — 粘贴一次,自动应用到 7 个 agent
#   4. 一键 import 完成,工作流卡片直接出现,可以派发
#
# 不用 UI 的人(命令行):
#   curl -X POST -H "Authorization: Bearer <token>" \\
#        -H "Content-Type: application/json" \\
#        -d "{\\"yaml\\": $(jq -Rs . < templates/bundles/personal-growth.yaml), \\"apiKey\\": \\"<your-deepseek-key>\\"}" \\
#        http://localhost:3000/api/admin/bundles/import
`

mkdirSync(dirname(BUNDLE_OUT), { recursive: true })
const bundleText = BUNDLE_BANNER + BUNDLE_DOC_COMMENT + '\n' + stringifyYaml(bundleDoc, yamlOpts)
writeFileSync(BUNDLE_OUT, bundleText)
console.log(`wrote ${BUNDLE_OUT}`)

mkdirSync(dirname(BUNDLE_STATIC), { recursive: true })
writeFileSync(BUNDLE_STATIC, bundleText)
console.log(`wrote ${BUNDLE_STATIC}`)

console.log(`\n${TEAM_AGENTS.length} agents | ${TEAM_AGENTS.filter(a => a.mcpServers).length} with mcpServers | ${TEAM_AGENTS.filter(a => a.uses.length > 1).length} with extra services`)
